import{t as e}from"./rolldown-runtime-H_PjY6_i.js";var a=e({T0001:()=>t,default:()=>r}),t={title:"Order Reporting",keywords:["Order Reporting","task reporting","order settlement","fraud ring reporting","internal declaration","ring settlement","task assignment","performance tracking","operation reporting"],aliases:["Baodan"],category:"Marketing Fraud",definition:"The act of a fraud ring member reporting completed illicit operations or transaction results to a superior for commission settlement or performance tracking.",description:"In marketing fraud operations, downstream actors report completed tasks such as fake orders or fraudulent registrations to a coordinator via internal communication tools. Managers then verify the workload and disburse corresponding payments, making this a critical step for internal profit-sharing and task management within the group. This process ensures the orderly execution of illegal activities and closes the benefit chain.",relatedRisks:["R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0021"],relatedAttackTools:[],relatedThreatActors:["TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},r={T0001:t},i=e({T0002:()=>n,default:()=>o}),n={title:"Fraudulent Anti-Counterfeit Claims",keywords:["Fraudulent Anti-Counterfeit Claims","fake review orchestration","disinformation campaign","reputation sabotage","fake anti-counterfeit","review manipulation","e-commerce sabotage","fake transaction orchestration","competitor sabotage"],aliases:[],category:"Marketing Fraud",definition:"A fraudulent attack by black market operators exploiting loopholes in e-commerce platform rules through fabricated transactions or data manipulation against merchants or the platform itself.",description:"Attackers typically organize large numbers of accounts to place malicious orders, initiate fake returns, or post batches of negative reviews targeting specific products or stores. This is done to extort merchants or fraudulently claim compensation from the platform. Such activities directly undermine market order, often leading to financial losses for merchants and store downgrades, representing a classic black market operation within the e-commerce ecosystem.",relatedRisks:["R0068","R0068-002","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0050","A0035","A0016","A0052","A0049","A0043","A0027"],relatedAttackTools:[],relatedThreatActors:["TA0034"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},o={T0002:n},s=e({T0003:()=>l,default:()=>d}),l={title:"Bulk Arbitrage Flip",keywords:["Bulk Arbitrage Flip","bulk buying arbitrage","promo scalping","price gap exploitation","bulk resale","promo arbitrage","scalper bulk buy","discount scalping","arbitrage flipping"],aliases:[],category:"Marketing Fraud",definition:"A large-scale fraudulent scheme where coupon hunters exploit high-value promotions or pricing errors on e-commerce platforms to buy goods at extremely low prices for resale and profit.",description:"Operators closely monitor platform promotional rule flaws and use automated scripts to instantly purchase large quantities of heavily discounted goods, hoarding them for resale at a markup through second-hand channels. This activity not only deprives legitimate consumers of benefits but can directly bankrupt merchants due to catastrophic financial losses, serving as a core profit-generating method for professional coupon hunters.",relatedRisks:["R0055","R0005","R0009","R0064"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0001-001"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},d={T0003:l},c=e({T0004:()=>u,default:()=>h}),u={title:"Dropshipping",keywords:["Dropshipping","order fulfillment","third-party fulfillment","logistics obscuring","fulfillment service","shipping proxy","blind dropshipping","package forwarding","order masking"],aliases:["Wearing Hair"],category:"Marketing Fraud",definition:"A link in the black market chain where a third-party drop-shipper provides actual logistics packages and shipping services for fake transactions or fraudulent orders.",description:"In fake order or fraud scenarios, to evade platform risk controls, the person placing the order does not possess real goods but entrusts a drop-shipper to send empty packages or cheap trinkets. The drop-shipper forges logistics information, providing realistic shipping traces for the fake transaction to fraudulently obtain platform subsidies or buyer trust.",relatedRisks:["R0004","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0021"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS02"],references:[{title:"2022互联网反舞弊:供应链腐败埋雷零售、科技、游戏行业_腾讯新闻"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},h={T0004:u},p=e({T0005:()=>g,default:()=>k}),g={title:"Big Score",keywords:["Big Score","high-value target","large-scale breach","big profit margin","high-value scheme","lucrative target","whale target","major score","big haul"],aliases:[],category:"Marketing Fraud",definition:"A target or single illicit gain with an exceptionally high profit margin and value in black market activities.",description:"Within coupon hunter or hacker circles, 'big meat' signifies the discovery of a severe platform vulnerability or a high-value, no-strings-attached promotion that the group can exploit for a massive, one-time profit. Such targets often involve financial payment loopholes or large-sum discount events, and a successful breach can cause catastrophic financial damage to the targeted enterprise.",relatedRisks:["R0009","R0055","R0064","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0001-001"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},k={T0005:g},f=e({T0006:()=>m,default:()=>y}),m={title:"Reverse Arbitrage Loss",keywords:["Reverse Arbitrage Loss","arbitrage loss","scalper loss","promo loss","failed flip","loss on promo","arbitrage fail","promo misjudgment"],aliases:["Anti-Halogen"],category:"Marketing Fraud",definition:"A situation where coupon hunters, while participating in promotions or exploiting loopholes, fail to recover their costs and incur a loss due to market downturns or operational errors.",description:"For example, the market price of hoarded physical goods plummets, or risk control triggers lead to frozen accounts and funds. This phenomenon of being 'fleeced by the platform instead' often occurs when black market groups miscalculate a promotion's value or encounter merchant order cancellations, serving as a self-deprecating term for a failed arbitrage attempt.",relatedRisks:["R0009","R0055","R0064","R0005"],relatedAvoidances:["A0020-003","A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0001-001"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},y={T0006:m},A=e({T0007:()=>b,default:()=>w}),b={title:"Carding Shop",keywords:["Carding Shop","carding marketplace","virtual goods shop","account shop","invite code shop","digital goods market","fraud tool shop","carding platform","underground marketplace"],aliases:[],category:"Marketing Fraud",definition:"An automated online consignment platform specifically for trading various black market virtual materials, accounts, and attack tools.",description:"These carding platforms are fundamental infrastructure for the black market, where merchants list illegal goods such as social media accounts, burner mobile SIMs, and phishing kits, allowing buyers to make fully automated purchases. This drastically lowers the barrier to entry for black market transactions, enabling fraudulent resources to circulate as easily as regular commodities, making it a central hub for money laundering and material distribution.",relatedRisks:["R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0006-005","A0016-002","A0051","A0037","A0050","A0035","A0016","A0052","A0049","A0024","A0054"],relatedAttackTools:["AT0027"],relatedThreatActors:[],relatedBusinessScenes:["BS02","BS04"],references:[{title:"Behind the Scale of Black and Gray Markets: The Resource Trading Network Formed by Carding Platforms",link:"https://www.163.com/dy/article/ED1Q6CVF0518STKV.html"},{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},w={T0007:b},T=e({T0008:()=>v,default:()=>R}),v={title:"Payout",keywords:["Payout","commission payout","task commission","rebate payout","payout settlement","task reimbursement","commission return","payout processing","participant payout"],aliases:["Return Home"],category:"Marketing Fraud",definition:"The act of an upstream taskmaster settling the advanced principal and commission to a downstream operator after a fake transaction or proxy order is completed.",description:"In scalper proxy purchasing or fake order fraud, the operator first advances their own money to buy designated goods. After receiving the goods or completing the task, the taskmaster 'returns the payment' via a payment tool. This sum typically includes the original price of the goods and the agreed-upon commission, serving as the direct financial incentive that keeps part-time black market participants engaged.",relatedRisks:["R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0021"],relatedAttackTools:[],relatedThreatActors:["TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},R={T0008:v},B=e({T0009:()=>D,default:()=>S}),D={title:"Fixed Payout",keywords:["Fixed Payout","fixed commission","task payout","predetermined payout","fixed rebate","fixed reward","task reward","fixed compensation","payout listing"],aliases:[],category:"Marketing Fraud",definition:"A fixed commission paid to participants upon completing marketing fraud tasks assigned by black-market operators.",description:"In organized marketing fraud schemes such as coupon exploitation and proxy purchasing, operators offer a predetermined fixed return to incentivize participants. The payout amount is clearly stated in the task instructions, and participants receive the fixed return after completing required actions like placing orders, receiving goods, or filing compensation claims. This model is commonly used in proxy purchasing and claims groups to quickly settle costs and profits, enabling fraud rings to extract platform subsidies at scale.",usageExample:"When a group task says 'fixed return 184,' it means that regardless of how much you actually pay upfront, you will get 184 back after completing the order according to the scheme.",relatedRisks:["R0003","R0005","R0070","R0009","R0055","R0064","R0068","R0068-002"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0043","A0027"],relatedAttackTools:[],relatedThreatActors:["TA0002","TA0001","TA0001-001","TA0034"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},S={T0009:D},L=e({T0010:()=>C,default:()=>F}),C={title:"Promo Abuser",keywords:["Promo Abuser","bonus abuser","coupon abuser","promo exploiter","cashback abuser","discount abuser","promo group","coupon stacking","offer abuser"],aliases:[],category:"Marketing Fraud",definition:"A term used within black-market circles to refer to downstream participants in marketing fraud, including homemakers, university students, and part-time workers.",description:"'Beggar friend' is a colloquial label used by fraud operators for the individuals who execute fraudulent tasks. These participants receive assignments through task groups and exploit platform loopholes or promotional rules to obtain goods, cashback, or compensation at minimal cost. Often operating multiple accounts, they collaborate with SIM card suppliers and scalpers to conduct bulk exploitation, serving as the operational layer of the fraud chain. Long-term involvement can lead to personal information leaks, account bans, and even legal liability.",relatedRisks:["R0003","R0005","R0070","R0009","R0055","R0064","R0068","R0068-002"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0043","A0027"],relatedAttackTools:[],relatedThreatActors:["TA0002","TA0001","TA0001-001","TA0034","TA0003","TA0004"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},F={T0010:C},x=e({T0011:()=>M,default:()=>I}),M={title:"Scalper Proxy Ordering",keywords:["Scalper Proxy Ordering","proxy buyer","order proxy","scalper gang","reseller proxy","bulk purchasing agent","purchasing script","limited release proxy","drop buyer"],aliases:[],category:"Marketing Fraud",definition:"A practice where fraud rings organize real users to remotely place orders, systematically circumventing purchase limits to acquire discounted goods for resale.",description:"In this model, upstream suppliers provide the purchasing scheme and funds, while downstream participants use their personal accounts to place orders to designated addresses. Once the goods arrive, the supplier collects and resells them. This method bypasses per-account purchase limits by using genuine users as ordering tools, enabling large-scale exploitation. Because the transactions are conducted by real individuals, they closely mimic legitimate consumer behavior, making detection by platforms more difficult.",relatedRisks:["R0049","R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},I={T0011:M},E=e({T0012:()=>z,default:()=>H}),z={title:"SMS Code Pickup",keywords:["SMS Code Pickup","SMS verification bypass","virtual number verification","PVA account creation","SMS forwarding service","burner phone verification","OTP interception","SMS relay","code-receiving platform"],aliases:[],category:"Marketing Fraud",definition:"The practice of obtaining SMS verification codes via specialized platforms to register accounts in bulk or bypass identity verification.",description:"SMS code reception is a core component of bulk account creation. SIM card suppliers use devices like modem pools to control numerous black-market SIM cards, and code-receiving platforms automatically forward verification codes to participants. These verified accounts are then used to exploit new-user promotions, participate in prize draws, or conduct fake transactions, severely undermining platform marketing rules. This activity is directly linked to the infringement of personal information and the broader cybercrime supply chain.",relatedRisks:["R0030","R0030-001","R0030-005","R0005"],relatedAvoidances:["A0007-001","A0015","A0059","A0061","A0044","A0007","A0016-003","A0024","A0021"],relatedAttackTools:["AT0006","AT0001-002","AT0004"],relatedThreatActors:["TA0003","TA0004"],relatedBusinessScenes:["BS02"],references:[{title:"2024 H1 Overseas E-commerce Platform Risk Research Report",link:"https://www.threathunter.cn/blog/2024-c4d0fcec-8464-4e21-a997-887ad34025d1"},{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},H={T0012:z},P=e({T0013:()=>O,default:()=>q}),O={title:"Empty Package",keywords:["Empty Package","fake shipment","brushing parcel","ghost package","dummy delivery","empty box shipping","synthetic tracking","phantom order fulfillment","void shipment"],aliases:[],category:"Marketing Fraud",definition:"A package sent during a fake transaction that contains no actual goods or is filled with irrelevant items.",description:"Empty packages are a common tactic in fake order brushing and false shipping. Sellers send empty packages to generate a logistics trail, creating the illusion of a completed transaction to fraudulently boost sales rankings and reputation scores. In marketing fraud, empty packages are also used to fabricate delivery records for proxy purchasing schemes, concealing the actual flow of goods. This constitutes direct transactional fraud.",relatedRisks:["R0004","R0017","R0017-001","R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0021"],relatedAttackTools:[],relatedThreatActors:["TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},q={T0013:O},U=e({T0014:()=>N,default:()=>W}),N={title:"Coupon Farming",keywords:["Coupon Farming","promo abuse","coupon clipping","bonus hunting","reward farming","promo code stacking","deal churning","offer harvesting","incentive abuse"],aliases:["Lu Mao"],category:"Marketing Fraud",definition:"The act of exploiting platform loopholes or promotional rules to obtain goods or services at zero or extremely low cost.",description:"'Wool pulling' is the execution phase in the marketing fraud chain. Participants use SMS-verified accounts, coupon stacking, and other methods to extract platform subsidies. Fraud rings organize large-scale wool-pulling activities through task groups, collecting the obtained goods for resale and profit. This behavior not only causes direct financial losses to platforms but also disrupts normal marketing order.",relatedRisks:["R0055","R0005","R0009","R0054-003","R0064","R0030","R0030-001"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0007","A0016-003","A0024","A0021"],relatedAttackTools:["AT0006"],relatedThreatActors:["TA0001","TA0001-001","TA0003"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},W={T0014:N},j=e({T0015:()=>V,default:()=>G}),V={title:"Direct Order",keywords:["Direct Order","no-discount order","rebate farming","cashback order","merchant kickback","direct rebate","order rebating","bare order","no-coupon purchase"],aliases:[],category:"Marketing Fraud",definition:"A task execution method where orders are placed at the original price without using any coupons or discounts.",description:"'Naked ordering' is common in scenarios where sellers are brushing their own sales volume or in proxy purchasing schemes. Participants place orders at full price, and the merchant later refunds the cost and pays a commission through rebates. This method circumvents platform risk controls that monitor coupon stacking, making the transaction appear more like a genuine purchase and reducing the risk of being flagged as fake.",relatedRisks:["R0017-001","R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},G={T0015:V},K=e({T0016:()=>Y,default:()=>Q}),Y={title:"SIM Bank",keywords:["SIM Bank","modem pool","SIM farm","SMS gateway","bulk SMS device","SIM box","GSM modem array","verification farm","SIM hosting"],aliases:[],category:"Marketing Fraud",definition:"Physical SIM cardsheld by card suppliers and inserted into modem pool devices for bulk sending and reception of SMS verification codes.",description:"Modem pool cards are the hardware foundation of the SMS code reception supply chain. Card suppliers use modem pool devices to control a large number of SIM cards simultaneously, providing verification code reception services to downstream black-market operations. These cards are often sourced from operator loopholes, illegally resold IoT cards, or identity fraud, and are widely used for bulk account registration and exploiting platform promotions. The existence of these cards allows fraud rings to bypass identity verification mechanisms at scale and low cost.",relatedRisks:["R0030","R0030-001","R0030-005","R0005"],relatedAvoidances:["A0007-001","A0015","A0059","A0061","A0044","A0007","A0016-003","A0024","A0021","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:["AT0004","AT0009","AT0006","AT0001-002"],relatedThreatActors:["TA0003","TA0004"],relatedBusinessScenes:["BS02"],references:[{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"},{title:"Black Market Big Data: 2024 Internet Underground Economy Trend Annual Review",link:"https://www.threathunter.cn/blog/2024-37b58782-063b-4426-a2f8-6de6622dbca7"},{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},Q={T0016:Y},X=e({T0017:()=>_,default:()=>J}),_={title:"Flash Sale",keywords:["Flash Sale","lightning deal","limited-time offer","flash discount","timed promotion","instant deal","doorbuster","time-limited sale","flash buying"],aliases:["Kill"],category:"Marketing Fraud",definition:"A form of marketing fraud in which illicit actors use automated tools to snap up promotional items at extreme speed during flash sales.",description:"Fraud rings deploy custom scripts or bot programs that complete the checkout process within milliseconds of a promotion going live, targeting limited-quantity discounted goods or voucher bundles. This prevents legitimate users from accessing the offers, severely undermines the fairness of marketing campaigns, and is often linked to downstream monetization channels for large-scale arbitrage.",usageExample:"During last night’s half-price liquor promotion, script operators flash-purchased hundreds of orders in seconds—we stood no chance trying to grab one manually.",relatedRisks:["R0012","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},J={T0017:_},Z=e({T0018:()=>$,default:()=>ee}),$={title:"Instant Sellout",keywords:["Instant Sellout","sold out instantly","out of stock immediately","instant depletion","zero inventory","immediate sellout","rapid sellout","instant clearance","gone in seconds"],aliases:["Meow"],category:"Marketing Fraud",definition:"The phenomenon in which popular items are instantly cleared out by illicit actors during marketing events, leaving ordinary users unable to make a purchase.",description:"Fraud rings use automated tools to place bulk orders within milliseconds of a sale opening, rapidly driving inventory to zero. This tactic is commonly employed for hoarding or resale for profit, severely disrupting platform sales operations and depriving average consumers of any buying opportunity.",usageExample:"Those limited-edition sneakers were gone the moment they dropped—definitely cleaned out by a group using bots again.",relatedRisks:["R0012","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},ee={T0018:$},ae=e({T0019:()=>te,default:()=>re}),te={title:"Aged Blank Account",keywords:["Aged Blank Account","clean account","fresh account","unused profile","zero-history account","virgin account","newly registered","blank profile","untouched account"],aliases:[],category:"Marketing Fraud",definition:"An account that has been registered for a full month and has no transaction history, prized by fraud rings for its low-risk profile in brushing operations.",description:"Because these accounts meet the required registration age and maintain a clean behavioral record, they can bypass entry-level risk controls that platforms apply to new accounts. After being acquired by fraud rings, they are commonly used for bulk order padding, fake reviews, or referral campaigns to collect platform marketing incentives at minimal cost, serving as a foundational resource for marketing fraud.",usageExample:"The platform’s risk controls have tightened lately and fresh accounts aren’t working well—we need to source a batch of clean month-old accounts to run tasks reliably.",relatedRisks:["R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0021"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},re={T0019:te},ie=e({T0020:()=>ne,default:()=>oe}),ne={title:"Compensation Abuse",keywords:["Compensation Abuse","refund fraud","malicious refunding","payout abuse","compensation scamming","refund exploit","claims abuse","refund churning","settlement abuse"],aliases:["Compensation Deputy"],category:"Marketing Fraud",definition:"The illicit practice of exploiting loopholes in platform after-sales policies to obtain unlawful profits through fraudulent refunds or compensation claims.",description:"Fraud rings target e-commerce policies such as no-reason returns, shipping insurance, or counterfeit compensation guarantees by fabricating product defects, conducting bait-and-switch returns, or posting malicious negative reviews to coerce merchants into cash settlements. This activity has evolved into an industrial chain that causes significant financial harm to sellers and disrupts market order.",usageExample:"Those groups specifically buy items covered by shipping insurance, then pick faults upon delivery to file compensation claims—they can pull in a fair amount of money each month.",relatedRisks:["R0068-002","R0068","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0043","A0027"],relatedAttackTools:[],relatedThreatActors:["TA0034"],relatedBusinessScenes:["BS02"],references:[{title:"Internet black and gray industry research report in the first half of 2024",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"},{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"}],updated:"2026-06-16"},oe={T0020:ne},se=e({T0021:()=>le,default:()=>de}),le={title:"Shield Bypass",keywords:["Shield Bypass","risk engine evasion","captcha bypass","bot detection bypass","WAF bypass","fingerprint spoofing","device spoofing","anti-fraud bypass","rule engine bypass"],aliases:[],category:"Marketing Fraud",definition:"The technical methods used by fraud operators to crack or circumvent a platform’s security and risk-control systems.",description:"Fraud technicians employ vulnerability scanning, protocol cracking, emulator-based device spoofing, and other techniques to defeat CAPTCHA challenges, device fingerprinting, and behavioral analysis. Successfully breaking through these defenses is a prerequisite for large-scale account registration, flash purchasing, or data scraping, making it the preparatory step for a wide range of cyberattacks and marketing fraud schemes.",usageExample:"This campaign just added device fingerprinting checks—if we don’t break through the shield first, our scripts won’t even be able to log in.",relatedRisks:["R0032-001","R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0010","A0010-002","A0021","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:["AT0007","AT0042"],relatedThreatActors:["TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},de={T0021:le},ce=e({T0022:()=>ue,default:()=>he}),ue={title:"Order Locking",keywords:["Order Locking","inventory hoarding","cart squatting","checkout hoarding","flash sale bot","cart locking","inventory denial","order reservation exploit"],aliases:["Lock Pill"],category:"Marketing Fraud",definition:"A tactic used by fraud rings during major e-commerce sales events in which they place bulk orders programmatically without completing payment to tie up inventory or promotional slots.",description:"After identifying pricing errors or high-value coupons, fraud rings use automated tools to instantly generate a large volume of pending orders that lock up the available stock. The intent is to hoard goods for resale at a higher price or to hold them for arbitrage, preventing both the merchant from selling normally and other consumers from making purchases.",usageExample:"Don’t rush to pay—first lock down all the low-priced inventory with orders; once the price rebounds, we can flip the order slots for a profit.",relatedRisks:["R0014","R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Internet black and gray industry research report in the first half of 2024",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"},{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"}],updated:"2026-06-16"},he={T0022:ue},pe=e({T0023:()=>ge,default:()=>ke}),ge={title:"Fake Follower Boosting",keywords:["Fake Follower Boosting","follower farming","social boosting","bot followers","follower inflation","mass account creation","influence inflation","follower botnet"],aliases:["Sofen"],category:"Marketing Fraud",definition:"The black-market practice of inflating a social media account’s follower count through bulk registration or purchase of fake accounts.",description:"Fraud rings leverage bot-farm control systems and SMS verification platforms to mass-produce zombie accounts that are then used to follow a designated target, creating an illusion of popularity. These fake followers typically generate no genuine engagement and are used to facilitate scam-driven traffic, exaggerate advertising performance, or defraud platform creator incentive programs, ultimately misleading real users or advertisers.",usageExample:"A new account going live gets no traffic—first find a channel to pad the follower count and make the storefront look credible, otherwise no one will trust you.",relatedRisks:["R0030","R0030-001","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0007","A0016-003","A0024","A0021","A0010","A0010-002","A0006-005","A0016-002","A0051","A0037"],relatedAttackTools:["AT0006"],relatedThreatActors:["TA0003"],relatedBusinessScenes:["BS02","BS04"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},ke={T0023:ge},fe=e({T0024:()=>me,default:()=>ye}),me={title:"Lossless Cashout",keywords:["Lossless Cashout","coupon liquidation","gift card cashout","voucher arbitrage","promo abuse cashout","coupon arbitrage","zero-cost cashout","promo code liquidation"],aliases:[],category:"Marketing Fraud",definition:"A scheme in which fraud rings exploit platform rule loopholes to convert vouchers or red packets into cash at near-zero cost.",description:"Through fictitious transactions, self-dealing, or collusion with merchants, fraud rings turn platform-issued coupons and shopping subsidies into real money. The operation requires no actual logistics or relies solely on empty-package shipping services, directly draining platform marketing funds and causing substantial financial losses to the platform.",usageExample:"There’s a loophole in this campaign—grab the vouchers and cash them out through a designated channel with almost no loss, turning a 100-yuan voucher into 95 in hand.",relatedRisks:["R0017","R0017-002","R0055","R0003","R0005","R0070"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0002"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},ye={T0024:me},Ae=e({T0025:()=>be,default:()=>we}),be={title:"No Shield",keywords:["No Shield","unprotected endpoint","risk control gap","unmonitored API","bypassable verification","missing rate limit","unshielded transaction"],aliases:[],category:"Marketing Fraud",definition:"A term used by fraud operators to describe a target platform that has no risk control measures in place.",description:'In underground fraud circles, a platform\'s risk control system is referred to as a "shield." "No shield" means the platform has not deployed effective security verification or anti-fraud strategies. This allows fraudsters to bypass defenses directly and conduct bulk operations, commonly used for large-scale harvesting of physical rewards, vouchers, or cash bonuses. The nature of a "shield" varies across business scenarios—such as a bank\'s hardware security token or an e-commerce platform\'s risk engine—but the absence of one signals an extremely low cost of attack.',relatedRisks:["R0005"],relatedAvoidances:["A0153","A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS02","BS01"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},we={T0025:be},Te=e({T0026:()=>ve,default:()=>Re}),ve={title:"Hardware Token",keywords:["Hardware Token","USB token","OTP token","hardware OTP","transaction signing token","2FA dongle","banking token","cryptographic token"],aliases:[],category:"Marketing Fraud",definition:"A verification mechanism deployed in e-commerce scenarios to prevent automated scripts from snapping up purchases.",description:'During flash sales or the release of popular items, fraud rings often deploy automated scripts to conduct bulk purchasing, disrupting normal transaction order. Platforms implement a "small shield" as a security checkpoint, requiring users to complete specific verifications to prove they are human operators, thereby blocking automated requests from bots. This mechanism serves as a critical line of defense against marketing fraud and protects the interests of legitimate users.',relatedRisks:["R0005"],relatedAvoidances:["A0001","A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},Re={T0026:ve},Be=e({T0027:()=>De,default:()=>Se}),De={title:"Profitable Target",keywords:["Profitable Target","high-value target","profitable exploit","lucrative promo","high-margin scheme","juicy target","high-ROI exploit"],aliases:[],category:"Marketing Fraud",definition:"A term used in underground fraud circles to indicate that a fraudulent activity or target offers high financial returns.",description:'Operators use "meat" as slang for profit. "Has meat" signifies that attacking a specific platform, participating in a marketing campaign, or executing a particular fraud technique can yield substantial illicit gains. Assessing whether a target "has meat" is the core criterion for fraud rings when deciding whether to commit resources and manpower to an attack. Campaigns involving high cashback, large no-threshold vouchers, or high-value physical gifts are typically flagged as targets that "have meat."',relatedRisks:["R0009","R0055","R0064","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0001-001"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},Se={T0027:De},Le=e({T0028:()=>Ce,default:()=>Fe}),Ce={title:"Cloud Blacklist",keywords:["Cloud Blacklist","T0028","Cloud Blacklist control","Cloud Blacklist risk","Cloud Blacklist detection","Cloud Blacklist governance","Cloud Blacklist keyword 7","Cloud Blacklist keyword 8","Cloud Blacklist keyword 9"],aliases:[],category:"Marketing Fraud",definition:"Accounts flagged and restricted by UnionPay QuickPass's risk control system, preventing them from participating in marketing campaigns.",description:'To combat marketing fraud, UnionPay QuickPass applies risk control flags to abnormal accounts, which are internally referred to as "cloud blacklisted." Once an account is placed on this blacklist, the user is barred from participating in any promotions, red packet giveaways, or lucky draws offered by the platform. When organizing coupon-harvesting operations, fraud rings prioritize non-blacklisted accounts for bulk actions to circumvent platform restrictions and ensure they can successfully drain marketing funds.',relatedRisks:["R0009","R0055","R0064","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0001-001"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},Fe={T0028:Ce},xe=e({T0029:()=>Me,default:()=>Ie}),Me={title:"One-Yuan Arbitrage Crew",keywords:["One-Yuan Arbitrage Crew","T0029","One-Yuan Arbitrage Crew control","One-Yuan Arbitrage Crew risk","One-Yuan Arbitrage Crew detection","One-Yuan Arbitrage Crew governance","One-Yuan Arbitrage Crew keyword 7","One-Yuan Arbitrage Crew keyword 8","One-Yuan Arbitrage Crew keyword 9"],aliases:[],category:"Marketing Fraud",definition:"A general term for coupon-harvesting groups obsessed with exploiting promotional offers to acquire goods or services at extremely low cost.",description:"Initially referring to users who only purchased one-yuan items, the term has evolved into a collective label for coupon harvesters, including demographics such as stay-at-home mothers, students, and part-time workers. They are highly active in various social groups, systematically collecting, sharing, and exploiting platform loopholes or promotional rules. By stacking vouchers and red packets, they achieve near-zero or zero-cost purchases. Their activities often operate in a grey area, and when scaled into organized operations, they become a link in the underground fraud supply chain.",relatedRisks:["R0005","R0009","R0055","R0064"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0001-001"],relatedBusinessScenes:["BS02","BS04"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},Ie={T0029:Me},Ee=e({T0030:()=>ze,default:()=>He}),ze={title:"High-Value Promo Exploit",keywords:["High-Value Promo Exploit","T0030","High-Value Promo Exploit control","High-Value Promo Exploit risk","High-Value Promo Exploit detection","High-Value Promo Exploit governance","High-Value Promo Exploit keyword 7","High-Value Promo Exploit keyword 8","High-Value Promo Exploit keyword 9"],aliases:[],category:"Marketing Fraud",definition:"Underground slang for an exceptionally profitable marketing loophole or coupon-harvesting opportunity.",description:'Within coupon-harvesting communities, a "lamb shank" refers to a single high-yield marketing campaign or platform vulnerability, distinct from the smaller, repeated gains known as "wool." Discovering a "lamb shank" signifies a major profit opportunity, causing information to spread rapidly through fraud networks and triggering massive, concentrated attacks that can inflict substantial financial losses on a platform within a short period.',usageExample:"Scored a massive lamb shank today. Using cards starting with 37 for purchases over 2500 gave a 137 discount. Found a ride organizer, all three accounts cashed out smoothly—the profit is insane. Spots are still open, brothers, get in fast!",relatedRisks:["R0003","R0005","R0070","R0009","R0055","R0064"],relatedAvoidances:["A0015","A0059","A0061","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0002","TA0001","TA0001-001"],relatedBusinessScenes:["BS02"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},He={T0030:ze},Pe=e({T0031:()=>Oe,default:()=>qe}),Oe={title:"Multi-Merchant Terminal",keywords:["Multi-Merchant Terminal","T0031","Multi-Merchant Terminal control","Multi-Merchant Terminal risk","Multi-Merchant Terminal detection","Multi-Merchant Terminal governance","Multi-Merchant Terminal keyword 7","Multi-Merchant Terminal keyword 8","Multi-Merchant Terminal keyword 9","Multi-Merchant Terminal keyword 10"],aliases:["One Chicken and Many Eggs"],category:"Marketing Fraud",definition:"The illegal practice of binding a single POS terminal to multiple merchant accounts for credit card cashing or limit maintenance.",description:"This operation violates UnionPay's one-machine-one-merchant regulation and is a common tactic used by coupon harvesters for credit card maintenance. By simulating multiple merchants across different industries on a single POS machine, cardholders can fabricate diversified spending records to evade bank risk controls and exploit rate differences between merchants to maximize credit card points or cashback rewards. This constitutes a regulatory violation or outright illegal act and is a form of financial fraud.",relatedRisks:["R0009","R0055","R0064","R0005"],relatedAvoidances:["A0015","A0059","A0061","A0044","A0024","A0016","A0054"],relatedAttackTools:[],relatedThreatActors:["TA0001","TA0001-001"],relatedBusinessScenes:["BS02","BS01"],references:[{title:"Black Market Big Data: E-commerce Scalper Industry Chain Analysis Report",link:"https://www.threathunter.cn/blog/fc4b4d8d000"},{title:"2024 H1 Internet Underground Economy Research Report",link:"https://www.threathunter.cn/blog/2024-50e66f87-abe6-4928-b031-c5c2c83c1cf0"}],updated:"2026-06-16"},qe={T0031:Oe},Ue=e({T0032:()=>Ne,default:()=>We}),Ne={title:"AB Loan Scam",keywords:["AB Loan Scam","T0032","AB Loan Scam control","AB Loan Scam risk","AB Loan Scam detection","AB Loan Scam governance","AB Loan Scam keyword 7","AB Loan Scam keyword 8","AB Loan Scam keyword 9"],aliases:[],category:"Credit Fraud",definition:"A fraudulent loan scheme that exploits individuals with good credit history to act as debt bearers for the actual borrower.",description:"Fraud rings target person A, who is desperate for cash but has poor credit, and lure them into recruiting person B, who has a clean credit profile, to act as a guarantor or nominal borrower. Intermediaries then fabricate documentation to help B secure a loan. The funds are used by A, but the debt and legal liability fall entirely on B. Ultimately, A and the intermediaries split the loan proceeds and disappear, leaving B saddled with massive debt under unknowing or coerced circumstances, often triggering severe social and financial risks.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},We={T0032:Ne},je=e({T0033:()=>Ve,default:()=>Ge}),Ve={title:"Proxy Loan",keywords:["Proxy Loan","T0033","Proxy Loan control","Proxy Loan risk","Proxy Loan detection","Proxy Loan governance","Proxy Loan keyword 7","Proxy Loan keyword 8","Proxy Loan keyword 9","Proxy Loan keyword 10"],aliases:["Bang Dai"],category:"Credit Fraud",definition:"The act of applying for a loan from a financial institution on behalf of another person without genuine borrowing intent, and then transferring the funds to that person.",description:"In a proxy loan scheme, the nominal borrower applies for the loan, signs the contract, and receives the disbursement, then passes the money to the actual user. A high-risk variant is AB lending, where the nominal borrower’s identity is used without their knowledge, leaving them with heavy debt. This model is often exploited by illicit intermediaries to defraud financial institutions, resulting in credit losses.",usageExample:"My friend’s credit was trashed and he couldn’t get a loan, so an agent had me do a proxy loan for him. I transferred the money as soon as it came through, and now it’s overdue—the bank keeps calling me.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ge={T0033:Ve},Ke=e({T0034:()=>Ye,default:()=>Qe}),Ye={title:"Credit Invisible",keywords:["Credit Invisible","T0034","Credit Invisible control","Credit Invisible risk","Credit Invisible detection","Credit Invisible governance","Credit Invisible keyword 7","Credit Invisible keyword 8","Credit Invisible keyword 9"],aliases:[],category:"Credit Fraud",definition:"An individual with no credit history in the credit reporting system, making it difficult for financial institutions to assess their risk.",description:"Because they have no borrowing history, credit invisibles are treated as high-value material by underground fraud rings and are openly traded on platforms like Telegram and X. Fraud syndicates use these identities to apply for loans or credit cards, bypassing risk models to commit large-scale credit fraud. Recruited as debt mules, these individuals often become part of the fraud chain unknowingly or under false promises and may ultimately face legal liability.",usageExample:"I’m short on cash lately and saw someone in a group recruiting credit invisibles to carry debt. They said I just need to sign a few papers and can get tens of thousands—does that sound legit?",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Desperados in Financial Fraud",link:"https://www.threathunter.cn/blog/f17db99edff"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Qe={T0034:Ye},Xe=e({T0035:()=>_e,default:()=>Je}),_e={title:"Error Code Fix",keywords:["Error Code Fix","T0035","Error Code Fix control","Error Code Fix risk","Error Code Fix detection","Error Code Fix governance","Error Code Fix keyword 7","Error Code Fix keyword 8","Error Code Fix keyword 9"],aliases:[],category:"Credit Fraud",definition:"A service offered by credit intermediaries claiming to resolve loan disbursement failures caused by specific error codes.",description:"When a financial institution’s system returns a risk-control error code that blocks loan disbursement, some intermediaries sell a fix service. They exploit internal loopholes, forge documents, or collude with insiders to override the restriction and force the disbursement. This practice usually involves high service fees and significantly increases the risk of subsequent loan fraud.",usageExample:"My application got rejected with error code E018. I found an agent who guarantees a fix for a 20% cut—not sure if they can really clear it.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Je={T0035:_e},Ze=e({T0036:()=>$e,default:()=>ea}),$e={title:"Credit Blank",keywords:["Credit Blank","T0036","Credit Blank control","Credit Blank risk","Credit Blank detection","Credit Blank governance","Credit Blank keyword 7","Credit Blank keyword 8","Credit Blank keyword 9"],aliases:[],category:"Credit Fraud",definition:"An individual with a completely blank credit file and no credit history whatsoever.",description:"A pure credit invisible has an even cleaner record than an ordinary credit invisible, making them more valuable in underground fraud circles and top-grade material for loan fraud and money laundering. Fraud rings recruit such individuals through social media, fabricate application profiles, and simultaneously apply for high-value loans from multiple institutions. Once the funds are obtained, the debt mule is often abandoned, leaving behind unrecoverable bad debt.",usageExample:"The agent said a pure credit invisible can get a bigger loan. He told me to give him my ID and he’d package the application—I’d get 30% of the payout. Is this a trap?",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049","A0024"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS04","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ea={T0036:$e},aa=e({T0037:()=>ta,default:()=>ra}),ta={title:"Loan Processing",keywords:["Loan Processing","T0037","Loan Processing control","Loan Processing risk","Loan Processing detection","Loan Processing governance","Loan Processing keyword 7","Loan Processing keyword 8","Loan Processing keyword 9"],aliases:[],category:"Credit Fraud",definition:"The capability or channel to manage the entire credit application process within underground fraud operations.",description:"In the context of credit fraud, the term refers not to a physical document but to an intermediary’s possession of the resources and methods to successfully secure a loan. Intermediaries package client profiles, clear approval hurdles, or exploit bank loopholes to complete the application. Having a direct line to the funding source or key approver means a higher success rate and steeper fees.",usageExample:"I’ve got a solid direct line—blacklisted or clean file, doesn’t matter. As long as there’s no court enforcement, I can get it approved. Fee negotiable.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ra={T0037:ta},ia=e({T0038:()=>na,default:()=>oa}),na={title:"Premium Card For Masses",keywords:["Premium Card For Masses","T0038","Premium Card For Masses control","Premium Card For Masses risk","Premium Card For Masses detection","Premium Card For Masses governance","Premium Card For Masses keyword 7","Premium Card For Masses keyword 8","Premium Card For Masses keyword 9"],aliases:[],category:"Credit Fraud",definition:"In credit card enthusiast slang, refers to three premium credit cards—Bank of Communications White Qilin, CMB Classic Platinum, and SPDB AE Platinum—that offer rich benefits and allow annual fees to be offset with points.",description:"These three cards are known for relatively accessible application thresholds and practical perks, leading ordinary cardholders to self-deprecatingly call them the 'loser's three white cards.' In underground circles, intermediaries often exploit bank easing periods or document fabrication techniques to help unqualified clients obtain these high-end cards, aiming to fraudulently secure high credit lines or resell points benefits.",usageExample:"SPDB AE Platinum has been easing approvals lately; the agent said among the loser's three white cards, this one offers the best value and can help me package my application to get approved.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},oa={T0038:na},sa=e({T0039:()=>la,default:()=>da}),la={title:"Credit Easing",keywords:["Credit Easing","T0039","Credit Easing control","Credit Easing risk","Credit Easing detection","Credit Easing governance","Credit Easing keyword 7","Credit Easing keyword 8","Credit Easing keyword 9"],aliases:[],category:"Credit Fraud",definition:"A period when a bank temporarily relaxes its credit approval standards, making it easier to get a loan or credit card approved.",description:"A loosening window is usually triggered by business pressure, policy adjustments, or system loopholes, and manifests as lower credit requirements, higher tolerance, or simplified processes. Underground intermediaries quickly detect such signals and organize bulk applications to defraud credit funds en masse. These windows are often short-lived, prompting agents to urge clients to act fast.",usageExample:"Inside info—XX Bank is loosening big time these next two days, ignoring inquiry counts. Get in quick before it closes.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},da={T0039:la},ca=e({T0040:()=>ua,default:()=>ha}),ua={title:"Anti-Collection",keywords:["Anti-Collection","T0040","Anti-Collection control","Anti-Collection risk","Anti-Collection detection","Anti-Collection governance","Anti-Collection keyword 7","Anti-Collection keyword 8","Anti-Collection keyword 9"],aliases:[],category:"Credit Fraud",definition:"The practice by underground organizations of helping debtors evade repayment obligations through forged documents, malicious complaints, and other illegal means.",description:"Operating under the guise of legal consulting, debt evasion rings incite debtors to default willfully. They forge poverty certificates and medical records or coach clients to file malicious complaints, pressuring financial institutions to grant debt relief or write off obligations. This behavior severely undermines the financial order; participants not only face debt recovery but may also be prosecuted for fraud.",usageExample:"I hired a legal consultant for debt evasion. They told me to forward all calls to them and said they could stop interest and suspend payments, but they took my money and blocked me.",relatedRisks:["R0096-001","R0068-001","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0029"],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ha={T0040:ua},pa=e({T0041:()=>ga,default:()=>ka}),ga={title:"Fake Provident Fund",keywords:["Fake Provident Fund","T0041","Fake Provident Fund control","Fake Provident Fund risk","Fake Provident Fund detection","Fake Provident Fund governance","Fake Provident Fund keyword 7","Fake Provident Fund keyword 8","Fake Provident Fund keyword 9","Fake Provident Fund keyword 10"],aliases:["Provident Fund Forgery"],category:"Credit Fraud",definition:"The practice of fabricating housing provident fund (HPF) contribution records—either by forging data or creating fictitious employment relationships—to fraudulently qualify for personal credit products offered by financial institutions.",description:"Fraud rings use technical means to spoof HPF app data or arrange backdated contributions through shell employment, enabling applicants to pass bank eligibility checks for consumer loans and salary-based loans. This tactic specifically targets credit products that rely on HPF data for risk assessment, allowing unqualified individuals to extract large sums. Once the fraud succeeds, the lender faces a direct bad-debt loss.",relatedRisks:["R0146","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Credit Fraud: Analysis of Provident Fund Forgery Loan Fraud Techniques",link:"https://www.threathunter.cn/blog/a6c71ff0534"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ka={T0041:ga},fa=e({T0042:()=>ma,default:()=>ya}),ma={title:"Credit Hungry",keywords:["Credit Hungry","T0042","Credit Hungry control","Credit Hungry risk","Credit Hungry detection","Credit Hungry governance","Credit Hungry keyword 7","Credit Hungry keyword 8","Credit Hungry keyword 9"],aliases:[],category:"Credit Fraud",definition:"An individual whose credit report shows a high volume of hard inquiries due to frequent applications for credit cards or loans.",description:"Because they have applied for multiple credit products in a short period, financial institutions view these individuals as higher-risk—either cash-strapped or exhibiting poor credit management. In underground lending contexts, such profiles are often targeted for “debt restructuring”: a fraud ring pays off their existing debts to temporarily clean their credit report, then immediately helps them apply for a batch of higher-limit loans. The victim ends up with a far heavier debt burden while the ring collects exorbitant service fees.",usageExample:"His credit report is full of inquiries—a classic over-inquired profile. No mainstream bank will approve him now.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ya={T0042:ma},Aa=e({T0043:()=>ba,default:()=>wa}),ba={title:"Credit Blacklist",keywords:["Credit Blacklist","T0043","Credit Blacklist control","Credit Blacklist risk","Credit Blacklist detection","Credit Blacklist governance","Credit Blacklist keyword 7","Credit Blacklist keyword 8","Credit Blacklist keyword 9"],aliases:[],category:"Credit Fraud",definition:"A person blacklisted by financial institutions due to severe adverse credit history, rendering them ineligible for any legitimate loan channel.",description:"These individuals typically have records of delinquency or default. Because fund flows through their accounts are hard to trace, their identities and accounts are frequently purchased or rented by fraud rings as money-laundering conduits. Rings also use blacklisted individuals’ personal information to conduct credential-stuffing attacks across multiple platforms, testing whether they can fraudulently apply for loans or credit products in the victim’s name. If successful, all resulting debt and liability fall on the original identity holder.",usageExample:"That identity is completely blacklisted now—no legitimate path works. It can only be used for running money.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049","A0024"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},wa={T0043:ba},Ta=e({T0044:()=>va,default:()=>Ra}),va={title:"Application Submission",keywords:["Application Submission","T0044","Application Submission control","Application Submission risk","Application Submission detection","Application Submission governance","Application Submission keyword 7","Application Submission keyword 8","Application Submission keyword 9"],aliases:[],category:"Credit Fraud",definition:"The operational step of submitting a prepared loan application package to a financial institution’s approval system.",description:"This is the critical juncture in the credit process where an application formally enters the review queue. In organized loan fraud, the submission stage often involves batch-uploading falsified documents, including fabricated corporate financial statements, personal bank statements, or fake housing provident fund records. Fraud rings use these packaged materials to systematically exploit specific risk-control rules and obtain high credit lines.",usageExample:"All these profiles have been seasoned. We’re submitting the whole batch tonight—aiming for full approval.",relatedRisks:["R0146","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ra={T0044:va},Ba=e({T0045:()=>Da,default:()=>Sa}),Da={title:"Fast Company Flip",keywords:["Fast Company Flip","T0045","Fast Company Flip control","Fast Company Flip risk","Fast Company Flip detection","Fast Company Flip governance","Fast Company Flip keyword 7","Fast Company Flip keyword 8","Fast Company Flip keyword 9"],aliases:[],category:"Credit Fraud",definition:"A scheme in which a fraud ring rapidly transfers a pre-seasoned shell company to a loan applicant through an untraceable change of ownership, circumventing rules that flag short-tenure legal representatives for business financing fraud.",description:"Fraud rings cultivate empty-shell companies with substantial operating revenue and tax invoice records in advance. Through manipulation, banks are unable to detect the true change of control via commercial registries. Once the applicant takes over, they can apply for multiple large-amount corporate tax-invoice loans within 20 to 45 days under the new legal-representative identity. The tactic exploits a time gap to concentrate large-scale fund extraction before the lender detects the anomaly.",usageExample:"Just took over a fast-transfer shell company—the data has been seasoned for six months. We’re pushing submissions hard over the next few days.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Desperados in Financial Fraud",link:"https://www.threathunter.cn/blog/f17db99edff"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Sa={T0045:Da},La=e({T0046:()=>Ca,default:()=>Fa}),Ca={title:"Exploit",keywords:["Exploit","T0046","Exploit control","Exploit risk","Exploit detection","Exploit governance","Exploit keyword 7","Exploit keyword 8","Exploit keyword 9","Exploit keyword 10"],aliases:["Button"],category:"Credit Fraud",definition:"A vulnerability or weak spot in a credit approval workflow or risk-control system that can be exploited for fraudulent gain.",description:"Underground operators specialize in reverse-engineering financial platforms’ review mechanisms to identify gaps, such as lax document verification or system response delays. Once a viable loophole is discovered, they mobilize teams to attack it at scale, batch-obtaining loans through forged documents and fake transactions. Information about these vulnerabilities is traded at high prices within closed fraud communities and spreads rapidly.",usageExample:"That newly launched consumer loan product has a loose loophole—no in-person interview required. Get people on it now.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Fa={T0046:Ca},xa=e({T0047:()=>Ma,default:()=>Ia}),Ma={title:"No-Collateral Loan",keywords:["No-Collateral Loan","T0047","No-Collateral Loan control","No-Collateral Loan risk","No-Collateral Loan detection","No-Collateral Loan governance","No-Collateral Loan keyword 7","No-Collateral Loan keyword 8","No-Collateral Loan keyword 9"],aliases:[],category:"Credit Fraud",definition:"A high-risk, unsecured loan issued without collateral or guarantees, typically by unlicensed underground lenders or private individuals operating outside the formal financial system.",description:"This lending model relies not on standard credit checks but on violent collection tactics to manage risk. In the context of credit fraud, such loans are often used to create debt traps through “borrow-new-to-pay-old” cycles or to provide short-term bridge funding for illicit operations. Once a borrower falls in, they face exorbitant interest rates and physical intimidation, making it extremely difficult to exit.",usageExample:"Those who get rejected by banks all turn to unsecured underground lenders. The interest is terrifyingly high, but you can get cash the same day.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:["TA0038"],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ia={T0047:Ma},Ea=e({T0048:()=>za,default:()=>Ha}),za={title:"Card Bust-Out",keywords:["Card Bust-Out","T0048","Card Bust-Out control","Card Bust-Out risk","Card Bust-Out detection","Card Bust-Out governance","Card Bust-Out keyword 7","Card Bust-Out keyword 8","Card Bust-Out keyword 9"],aliases:[],category:"Credit Fraud",definition:"A form of credit card fraud in which the cardholder deliberately maxes out the credit line through spending, cash advances, or installment plans and then intentionally defaults on all repayment obligations.",description:"Operators exhaust the entire credit limit through large purchases, cash-out schemes, or installment-based consumption and then refuse to make any payments. Common methods include applying for cards with synthetic identities and draining them immediately, or using cyclic cash-out techniques to funnel the funds into illegal activities. This practice directly causes bad-debt losses for the issuing institution and is a classic modus operandi in credit card fraud.",usageExample:"All cards obtained from that batch of identities are treated as empty-card runs—drain them and dump them. No one thinks about repayment.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ha={T0048:za},Pa=e({T0049:()=>Oa,default:()=>qa}),Oa={title:"Loan Farming",keywords:["Loan Farming","T0049","Loan Farming control","Loan Farming risk","Loan Farming detection","Loan Farming governance","Loan Farming keyword 7","Loan Farming keyword 8","Loan Farming keyword 9"],aliases:[],category:"Credit Fraud",definition:"Loan harvesting refers to the fraudulent practice of applying for small online loans in bulk using fabricated credentials with no intention of repayment.",description:"Fraudsters use synthetic or stolen identities, forged income proofs, and fake employment records to apply for loans across multiple platforms simultaneously. Once the funds are disbursed, they immediately sever contact and default, leaving financial institutions with bad debt. This tactic often targets small, fast-approval cash loan products with weak risk controls and is a classic form of loan fraud.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},qa={T0049:Oa},Ua=e({T0050:()=>Na,default:()=>Wa}),Na={title:"Naked Application",keywords:["Naked Application","T0050","Naked Application control","Naked Application risk","Naked Application detection","Naked Application governance","Naked Application keyword 7","Naked Application keyword 8","Naked Application keyword 9"],aliases:[],category:"Credit Fraud",definition:"Naked application refers to the practice of applying for a credit card or loan by submitting only a basic form without any supporting documentation.",description:"Applicants deliberately withhold proof of assets, income, or other supplementary materials, exploiting the lenient underwriting thresholds of certain products. Fraud rings commonly use this method to test banks' or platforms' approval loopholes at scale, screening for channels with weak risk controls to pave the way for subsequent large-scale fraud.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Wa={T0050:Na},ja=e({T0051:()=>Va,default:()=>Ga}),Va={title:"Slow Company Flip",keywords:["Slow Company Flip","T0051","Slow Company Flip control","Slow Company Flip risk","Slow Company Flip detection","Slow Company Flip governance","Slow Company Flip keyword 7","Slow Company Flip keyword 8"],aliases:[],category:"Credit Fraud",definition:"Slow-cooked enterprise refers to a scheme where fraud rings acquire and long-term package shell companies to defraud banks of large tax-invoice loans.",description:"Fraud rings formally transfer the legal representative role of a shell company to a debt mule and wait out the bank's required 3-6 month change-of-ownership period. During this time, they fabricate business transaction records, invoicing, and tax payments to portray the company as a normally operating, high-quality client. This is done to bypass risk models and secure high-limit business loans, after which they default on the debt.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Desperados in Financial Fraud",link:"https://www.threathunter.cn/blog/f17db99edff"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ga={T0051:Va},Ka=e({T0052:()=>Ya,default:()=>Qa}),Ya={title:"Grocery Card",keywords:["Grocery Card","T0052","Grocery Card control","Grocery Card risk","Grocery Card detection","Grocery Card governance","Grocery Card keyword 7","Grocery Card keyword 8"],aliases:[],category:"Credit Fraud",definition:"Grocery card refers to a bank card used by fraud rings for daily small-amount cash-outs or money laundering activities.",description:"Fraud rings use these cards to conduct low-value, high-frequency sham transactions at merchants, simulating everyday spending like grocery shopping to evade risk controls. These cards are often sourced illegally and are used to clean illicit funds from scams or gambling by breaking them into small amounts. Once the card is flagged by risk controls, any remaining funds are rapidly transferred out.",usageExample:"He uses a batch of grocery cards to make dozens of small transactions at convenience stores every day, cleaning money from telecom fraud a few dozen bucks at a time.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0024","A0016","A0061"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Qa={T0052:Ya},Xa=e({T0053:()=>_a,default:()=>Ja}),_a={title:"Internal Kickback",keywords:["Internal Kickback","T0053","Internal Kickback control","Internal Kickback risk","Internal Kickback detection","Internal Kickback governance","Internal Kickback keyword 7","Internal Kickback keyword 8"],aliases:[],category:"Credit Fraud",definition:"Internal kickback refers to the commission paid to internal employees or intermediaries who facilitate fraudulent loans.",description:"In the loan fraud chain, internal kickbacks are the illicit payments that motivate bank insiders or loan brokers to violate procedures. To secure these high commissions, they actively help fraud rings fabricate application materials, relax review standards, or even directly use their internal access to approve high-risk applications, leading to significant bad debt.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS02","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ja={T0053:_a},Za=e({T0054:()=>$a,default:()=>et}),$a={title:"Company Incubation",keywords:["Company Incubation","T0054","Company Incubation control","Company Incubation risk","Company Incubation detection","Company Incubation governance","Company Incubation keyword 7","Company Incubation keyword 8"],aliases:[],category:"Credit Fraud",definition:"Enterprise incubation refers to the practice of registering or acquiring shell companies in bulk and fabricating operational data to fraudulently obtain business loans.",description:"Fraud rings purchase dormant companies or register new shells, then generate fake invoices, transaction flows, and tax records for them. After months of packaging, these companies appear to be stable businesses, but are actually used to apply for large tax-invoice loans from banks. Once the funds are received, they are immediately transferred through multiple accounts, and the debt is ultimately defaulted on.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},et={T0054:$a},at=e({T0055:()=>tt,default:()=>rt}),tt={title:"7-14 Payday Trap",keywords:["7-14 Payday Trap","T0055","7-14 Payday Trap control","7-14 Payday Trap risk","7-14 Payday Trap detection","7-14 Payday Trap governance","7-14 Payday Trap keyword 7","7-14 Payday Trap keyword 8"],aliases:[],category:"Credit Fraud",definition:"7-14 high-interest loan refers to an illegal, ultra-high-interest loan with a 7- or 14-day term that charges exorbitant upfront fees and overdue penalties.",description:"Illegal lending platforms operated by fraud rings lure victims with promises of unsecured, instant loans. In reality, they deduct over 30% in upfront fees at disbursement. Borrowers who default face aggressive debt collection and punitive penalty interest. This model is often accompanied by the illegal harvesting of contact lists, which is used to threaten borrowers, making it a classic trap loan scheme.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},rt={T0055:tt},it=e({T0056:()=>nt,default:()=>ot}),nt={title:"Car Loan Cash-Out",keywords:["Car Loan Cash-Out","T0056","Car Loan Cash-Out control","Car Loan Cash-Out risk","Car Loan Cash-Out detection","Car Loan Cash-Out governance","Car Loan Cash-Out keyword 7","Car Loan Cash-Out keyword 8"],aliases:[],category:"Credit Fraud",definition:"Car financing fraud refers to the act of using falsified documents to fraudulently obtain an auto loan and then cashing out the vehicle.",description:"Fraud rings recruit credit mules with clean records and fabricate their employment and income proofs. They use these fake profiles to secure a loan from a financial institution under the pretense of buying a car. Once the vehicle is acquired, it is not used but is immediately pawned or sold for cash. The loan is then abandoned, resulting in a bad debt for the auto loan.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ot={T0056:nt},st=e({T0057:()=>lt,default:()=>dt}),lt={title:"Loan Sharking",keywords:["Loan Sharking","T0057","Loan Sharking control","Loan Sharking risk","Loan Sharking detection","Loan Sharking governance","Loan Sharking keyword 7","Loan Sharking keyword 8"],aliases:[],category:"Credit Fraud",definition:"In the context of credit fraud, this refers to illegal high-interest loans specifically issued to gamblers.",description:"These loans are typically provided by individuals operating near casinos or by affiliates of online gambling platforms. They carry extremely high interest rates calculated on a daily or weekly basis. Lenders target desperate gamblers who have lost heavily and are seeking to recoup their losses. When borrowers fail to repay, violent debt collection or coercion is often used. Such capital flows are frequently linked to money laundering and underground banking, easily leading to secondary crimes.",usageExample:"He lost everything at the casino last night and borrowed 100,000 in loan shark money from a lender on the floor, agreeing to repay 130,000. A week later, he still hadn't paid it back and debt collectors were at his door.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0024","A0016","A0061"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},dt={T0057:lt},ct=e({T0058:()=>ut,default:()=>ht}),ut={title:"Double Blacklist",keywords:["Double Blacklist","T0058","Double Blacklist control","Double Blacklist risk","Double Blacklist detection","Double Blacklist governance","Double Blacklist keyword 7","Double Blacklist keyword 8"],aliases:[],category:"Credit Fraud",definition:"Refers to a personal credit report containing multiple severe negative records, such as serious delinquencies and court-enforced dishonesty judgments.",description:"Fraud rings often use this term to precisely target and lock in desperate borrowers. As these individuals cannot obtain loans through legitimate channels, they become 'prime customers' for illicit brokers. These brokers assist them in defrauding loans by fabricating application materials and exploiting bank approval loopholes, charging high fees in the process, which ultimately leads to a surge in bad debt risk for financial institutions.",usageExample:"The broker posted an ad in the group saying, 'Specializing in loans for the double-blacklisted, credit history irrelevant, anyone welcome.' It was just a trick to get people with ruined credit to apply for loans.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ht={T0058:ut},pt=e({T0059:()=>gt,default:()=>kt}),gt={title:"Shell Company",keywords:["Shell Company","T0059","Shell Company control","Shell Company risk","Shell Company detection","Shell Company governance","Shell Company keyword 7","Shell Company keyword 8"],aliases:[],category:"Credit Fraud",definition:"A fraudulent scheme where criminals use a shell company with no actual operations as a disguise to fraudulently obtain loans or credit lines.",description:"Fraudsters first acquire or register a seemingly normal company, then fabricate transaction records and financial statements to make it appear as a high-quality enterprise. This 'shell' is then used to apply for loans or acceptance bills from multiple financial institutions. Once the funds are secured, the money is quickly transferred and the company is dissolved. This method is highly covert and often leaves credit institutions facing massive bad debts.",usageExample:"Their team specializes in recruiting rural elderly people to register companies using their IDs. After running fake transactions for six months, they start shell company loan fraud. By the time the bank catches on, the company is long gone.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},kt={T0059:gt},ft=e({T0060:()=>mt,default:()=>yt}),mt={title:"Exploit-Based Credit Application",keywords:["Exploit-Based Credit Application","T0060","Exploit-Based Credit Application control","Exploit-Based Credit Application risk","Exploit-Based Credit Application detection","Exploit-Based Credit Application governance","Exploit-Based Credit Application keyword 7","Exploit-Based Credit Application keyword 8"],aliases:[],category:"Credit Fraud",definition:"The illegal practice of exploiting loopholes in bank risk control or policy differences to bypass standard approval processes and fraudulently obtain credit cards or loans.",description:"Operators typically study the varying approval strictness across different banks or regions, exploiting system vulnerabilities to submit false information or apply from a different location. Upon a successful 'border crossing,' they quickly max out the credit line and abandon the card, causing direct bad debt losses for the bank. This behavior severely disrupts the financial credit order and is a primary target for anti-fraud departments.",usageExample:"The risk control on that loan product has been lax lately. The group chats are full of tutorials on how to sneak through, using fake addresses for cross-regional applications, and the approval rate is pretty high.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},yt={T0060:mt},At=e({T0061:()=>bt,default:()=>wt}),bt={title:"Fee Refund Abuse",keywords:["Fee Refund Abuse","T0061","Fee Refund Abuse control","Fee Refund Abuse risk","Fee Refund Abuse detection","Fee Refund Abuse governance","Fee Refund Abuse keyword 7","Fee Refund Abuse keyword 8","Fee Refund Abuse keyword 9"],aliases:[],category:"Credit Fraud",definition:"A scheme where illicit actors use malicious complaints or forged documents to coerce financial institutions into refunding various legally charged fees.",description:"Posing as 'agent advocates,' fraud rings instigate clients or directly act on their behalf to file mass complaints with regulatory bodies. They exploit the financial institution's desire to avoid trouble, demanding refunds of interest, service fees, or even principal, and then take a large commission. Such malicious complaints not only disrupt the financial order but also crowd out legitimate complaint channels for ordinary consumers.",usageExample:"A broker helped him get all the interest from his online loan refunded and took a 30% cut. He was then told to refer everyone in his contact list for the same fee refund scam.",relatedRisks:["R0068-001","R0096","R0096-001"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0029"],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Credit Fraud: Exposing the Underground Industry Behind Illegal Proxy Rights-Protection Schemes",link:"https://www.threathunter.cn/blog/e78513e348b"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},wt={T0061:bt},Tt=e({T0062:()=>vt,default:()=>Rt}),vt={title:"Online Lending",keywords:["Online Lending","T0062","Online Lending control","Online Lending risk","Online Lending detection","Online Lending governance","Online Lending keyword 7","Online Lending keyword 8","Online Lending keyword 9","Online Lending keyword 10"],aliases:["WWD"],category:"Credit Fraud",definition:"Refers to small loans issued through internet platforms, which are frequently exploited by fraud rings for fraudulent applications.",description:"Fraud rings use synthetic or stolen identities to register for and apply to various online lending products in bulk. They typically target small, cash-advance platforms with weak risk controls, maliciously cashing out through a practice known as 'loan farming' and then disappearing after the loan is disbursed. This behavior leads to massive bad debts for online lending platforms and is a contributing factor to the violent debt collection chaos.",usageExample:"He created a bunch of fake profiles to specifically target online loan products that don't check credit history. Any money he got was considered a 'payday,' and he never intended to pay it back.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Rt={T0062:vt},Bt=e({T0063:()=>Dt,default:()=>St}),Dt={title:"Credit Profile Dilution",keywords:["Credit Profile Dilution","T0063","Credit Profile Dilution control","Credit Profile Dilution risk","Credit Profile Dilution detection","Credit Profile Dilution governance","Credit Profile Dilution keyword 7","Credit Profile Dilution keyword 8","Credit Profile Dilution keyword 9"],aliases:[],category:"Credit Fraud",definition:"Describes a personal credit profile that has become extremely chaotic and poor due to frequent applications for online loans, as reflected in big data credit checks.",description:"These users typically apply for loans on multiple platforms in a short period, leaving a trail of numerous credit inquiries and debt records. Fraud brokers view these 'credit-messed' users as potential clients, selling them services like 'big data cleanup' or 'forced loan approval.' In reality, this chaotic data state is very difficult to fix, and users often fall into a vicious cycle of taking out new loans to pay old ones.",usageExample:"His credit is completely messed up now, so all legitimate platforms reject him. He can only go to shady brokers for a long shot, which just makes his credit worse until he's totally blacklisted.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},St={T0063:Dt},Lt=e({T0064:()=>Ct,default:()=>Ft}),Ct={title:"Debt Relief Scam",keywords:["Debt Relief Scam","T0064","Debt Relief Scam control","Debt Relief Scam risk","Debt Relief Scam detection","Debt Relief Scam governance","Debt Relief Scam keyword 7","Debt Relief Scam keyword 8","Debt Relief Scam keyword 9"],aliases:[],category:"Credit Fraud",definition:"An illicit agency service that fraudulently profits under the guise of debt optimization, using methods like document forgery and malicious complaints.",description:"Under the pretext of 'legal aid,' fraud rings offer agency services for debt relief, such as stopping interest accrual or negotiating installment plans. They pressure financial institutions by forging documents like poverty certificates or hospital records, and even instigate clients to default maliciously. This operation not only defrauds clients of high service fees but also exposes financial institutions to compliance risks, undermining the normal credit order.",usageExample:"He paid a broker ten thousand for debt optimization, which just meant the broker forged fake hardship documents to negotiate with the bank. In the end, the bank called the police, and all his accounts were frozen.",relatedRisks:["R0096-001","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0029"],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Credit Fraud: Exposing the Underground Industry Behind Illegal Proxy Rights-Protection Schemes",link:"https://www.threathunter.cn/blog/e78513e348b"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ft={T0064:Ct},xt=e({T0065:()=>Mt,default:()=>It}),Mt={title:"Straw Borrower",keywords:["Straw Borrower","T0065","Straw Borrower control","Straw Borrower risk","Straw Borrower detection","Straw Borrower governance","Straw Borrower keyword 7","Straw Borrower keyword 8","Straw Borrower keyword 9"],aliases:[],category:"Credit Fraud",definition:"A professional debt mule is an individual recruited by fraud rings to take out loans under their own name in exchange for a small cut of the proceeds, while bearing full liability for the debt.",description:"These individuals typically have clean credit histories but are in urgent need of money. After being coached by fraud intermediaries, they apply for auto loans, mortgages, personal credit, or business loans in their own name. Once the funds are disbursed, the bulk of the money is siphoned off by the orchestrating gang, leaving the debt mule with a small share while they shoulder the entire debt burden and credit damage. This scheme is common in organized loan fraud, ultimately resulting in bad debt for financial institutions and legal liability and credit ruin for the mule.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"}],updated:"2026-06-16"},It={T0065:Mt},Et=e({T0066:()=>zt,default:()=>Ht}),zt={title:"Resold Data",keywords:["Resold Data","T0066","Resold Data control","Resold Data risk","Resold Data detection","Resold Data governance","Resold Data keyword 7","Resold Data keyword 8","Resold Data keyword 9"],aliases:[],category:"Data Leakage",definition:"Second-hand data refers to personal or corporate data that has been resold one or more times in illicit data trading markets.",description:"Due to repeated reselling, this data often suffers from missing fields, outdated information, or tampering, significantly reducing its accuracy and validity. In the underground supply chain, second-hand data is typically used for broad-stroke scams or low-quality marketing campaigns. Its trading price is far lower than that of fresh data, and buyers are usually downstream fraudsters with limited budgets.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Ht={T0066:zt},Pt=e({T0067:()=>Ot,default:()=>qt}),Ot={title:"Broad-Sweep Data",keywords:["Broad-Sweep Data","T0067","Broad-Sweep Data control","Broad-Sweep Data risk","Broad-Sweep Data detection","Broad-Sweep Data governance","Broad-Sweep Data keyword 7","Broad-Sweep Data keyword 8","Broad-Sweep Data keyword 9"],aliases:[],category:"Data Leakage",definition:"Bulk data refers to a broad, unfiltered collection of personal information with low precision, traded in illicit data markets.",description:"This type of data usually comes from messy sources and contains a high volume of invalid, duplicate, or erroneous records, lacking any specific targeting. After purchasing bulk data, fraudsters often need to invest additional effort in cleaning and filtering before it can be used for scams or marketing. Due to its extremely low conversion rate, bulk data is cheap on the market and is commonly used for low-level attacks such as mass phishing SMS blasts.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0007","A0016-003","A0024","A0021","A0006-005","A0016-002","A0051","A0037","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},qt={T0067:Ot},Ut=e({T0068:()=>Nt,default:()=>Wt}),Nt={title:"Refreshed Data",keywords:["Refreshed Data","T0068","Refreshed Data control","Refreshed Data risk","Refreshed Data detection","Refreshed Data governance","Refreshed Data keyword 7","Refreshed Data keyword 8","Refreshed Data keyword 9"],aliases:[],category:"Data Leakage",definition:"Refurbished data refers to old data that has been processed and disguised as new data in illicit data trading.",description:"Fraudsters repackage outdated data by supplementing it with fabricated information, altering timestamps, or deduplicating records. On the surface, this data appears fresh and valid, but the core information is stale, often leading to failed scams or blocked marketing efforts when used by buyers. Refurbished data is commonly used to deceive downstream buyers by passing off inferior goods as high-quality, reaping excessive profits.",relatedRisks:["R0016","R0189","R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Wt={T0068:Nt},jt=e({T0069:()=>Vt,default:()=>Gt}),Vt={title:"Subsidy Recipient Data",keywords:["Subsidy Recipient Data","T0069","Subsidy Recipient Data control","Subsidy Recipient Data risk","Subsidy Recipient Data detection","Subsidy Recipient Data governance","Subsidy Recipient Data keyword 7","Subsidy Recipient Data keyword 8","Subsidy Recipient Data keyword 9"],aliases:[],category:"Data Leakage",definition:"Subsidy data refers to personal information related to recipients of government poverty alleviation programs, traded in illicit data markets.",description:"This data typically contains detailed identity, address, and subsidy information of low-income individuals, illegally obtained and resold by underground actors. Downstream buyers exploit this data to carry out targeted scams against vulnerable groups with weak awareness, such as impersonating poverty alleviation offices to issue fake subsidies. Due to the high authenticity of the data, such scams have a high success rate and cause severe social harm.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Gt={T0069:Vt},Kt=e({T0070:()=>Yt,default:()=>Qt}),Yt={title:"Overnight Data",keywords:["Overnight Data","T0070","Overnight Data control","Overnight Data risk","Overnight Data detection","Overnight Data governance","Overnight Data keyword 7","Overnight Data keyword 8","Overnight Data keyword 9"],aliases:[],category:"Data Leakage",definition:"Aged data refers to data that attackers deliberately delay selling for a period after exfiltrating it, in illicit data trading.",description:"To evade risk tracking or wait for the heat to die down, attackers hoard freshly stolen data for a while before releasing it onto the black market. This delayed transaction severely lags the discovery of and response to the data breach, causing victims to suffer ongoing losses often without their knowledge. Aged data is frequently used for highly targeted scams and is favored by underground actors for its strong stealth.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Qt={T0070:Yt},Xt=e({T0071:()=>_t,default:()=>Jt}),_t={title:"Stock Investor Data",keywords:["Stock Investor Data","T0071","Stock Investor Data control","Stock Investor Data risk","Stock Investor Data detection","Stock Investor Data governance","Stock Investor Data keyword 7","Stock Investor Data keyword 8"],aliases:[],category:"Data Leakage",definition:"Investor data refers to personal information specifically tailored for targeting stock investors, traded in illicit data markets.",description:"This data precisely targets high-net-worth or active retail investors and contains sensitive information such as investment preferences and portfolio holdings. Fraud rings use this data to carry out stock recommendation scams, pump-and-dump schemes, and other illegal activities, with single fraud amounts often being substantial. Due to its high conversion rate and strong monetization potential, investor data is a high-value commodity in darknet trading.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS01","BS02","BS04"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Jt={T0071:_t},Zt=e({T0072:()=>$t,default:()=>er}),$t={title:"Skimmed Card Data",keywords:["Skimmed Card Data","T0072","Skimmed Card Data control","Skimmed Card Data risk","Skimmed Card Data detection","Skimmed Card Data governance","Skimmed Card Data keyword 7","Skimmed Card Data keyword 8"],aliases:[],category:"Data Leakage",definition:"Track data refers to bank card magnetic stripe information obtained through skimming devices installed on compromised POS terminals, traded in illicit data markets.",description:"By implanting skimming modules in POS terminals, fraudsters steal magnetic stripe data and PINs from bank cards. This data is extremely precise and can be directly used to clone cards for fraudulent transactions or sold to downstream gangs for telecom fraud. Track data is core financial information, and its leakage directly threatens the financial security of cardholders.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049","A0024","A0054"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS01"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},er={T0072:$t},ar=e({T0073:()=>tr,default:()=>rr}),tr={title:"Fresh Data",keywords:["Fresh Data","T0073","Fresh Data control","Fresh Data risk","Fresh Data detection","Fresh Data governance","Fresh Data keyword 7"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to personal or organizational information that is still valid and can be immediately used for fraudulent activities.",description:"This type of data is typically the latest leaked or stolen first-hand information, not yet resold multiple times, and has a high verification success rate. After purchasing it, underground practitioners can directly use it for targeted scams, unauthorized transactions, or account takeovers without additional cleaning. Due to its timeliness, its price on dark web forums and Telegram groups is significantly higher than that of expired data.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},rr={T0073:tr},ir=e({T0074:()=>nr,default:()=>or}),nr={title:"Precision Data",keywords:["Precision Data","T0074","Precision Data control","Precision Data risk","Precision Data detection","Precision Data governance","Precision Data keyword 7"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to personal information or account credentials that have been meticulously filtered and verified, possessing extremely high authenticity.",description:"This data often includes detailed contact information, asset status, or specific consumption records, cleaned and annotated by specialized groups. Fraudsters exploit its high accuracy to conduct targeted phishing or business fraud, with success rates far exceeding ordinary data. In underground market transactions, this data is often sold at a high price per record and is a core tool leading to substantial financial losses.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0006-005","A0016-002","A0051","A0037","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},or={T0074:nr},sr=e({T0075:()=>lr,default:()=>dr}),lr={title:"Leaked Data",keywords:["Leaked Data","T0075","Leaked Data control","Leaked Data risk","Leaked Data detection","Leaked Data governance","Leaked Data keyword 7"],aliases:[],category:"Data Leakage",definition:"In the context of the underground industry, broadly refers to various types of sensitive data illegally obtained and used for profit.",description:"This data encompasses personal information, corporate secrets, login credentials, and more, serving as the foundational resource for online fraud, unauthorized transactions, and marketing scams. Within the underground supply chain, this data is often resold multiple times, processed from raw data into refined, high-value data, and ultimately used by downstream criminal groups for monetization.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:["AT0012"],relatedThreatActors:["TA0005","TA0020","TA0040"],relatedBusinessScenes:["BS00","BS01","BS02","BS04"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},dr={T0075:lr},cr=e({T0076:()=>ur,default:()=>hr}),ur={title:"Niche Data",keywords:["Niche Data","T0076","Niche Data control","Niche Data risk","Niche Data detection","Niche Data governance","Niche Data keyword 7"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to personal or corporate information with low market demand that is difficult to monetize.",description:"This data may be of little interest to underground practitioners due to the target group's weak purchasing power, outdated information, or narrow application scenarios. Such data is often sold off cheaply in bulk or bundled with other high-value data, used to fill databases or for low-cost, wide-net scams.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},hr={T0076:ur},pr=e({T0077:()=>gr,default:()=>kr}),gr={title:"Raw Data",keywords:["Raw Data","T0077","Raw Data control","Raw Data risk","Raw Data detection","Raw Data governance","Raw Data keyword 7"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to raw, leaked data that has not been cleaned, filtered, or categorized.",description:"This data typically contains a large amount of redundant, duplicate, or invalid information, making direct use highly inefficient. Data brokers or technical groups in the underground economy purchase this raw data, clean and process it through methods like credential stuffing and cross-referencing, extract valid fields, and then resell it at a markup to downstream fraud or marketing teams.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},kr={T0077:gr},fr=e({T0078:()=>mr,default:()=>yr}),mr={title:"Maternal-and-Infant Data",keywords:["Maternal-and-Infant Data","T0078","Maternal-and-Infant Data control","Maternal-and-Infant Data risk","Maternal-and-Infant Data detection","Maternal-and-Infant Data governance","Maternal-and-Infant Data keyword 7"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to personal information and consumption data related to pregnant women, new mothers, and infants.",description:"This data includes maternal health records, infant birth registrations, and baby product purchase lists, leaked from channels such as hospitals and e-commerce platforms. After acquiring it, underground groups resell it to confinement centers and photography studios for telemarketing harassment, or directly use it for targeted scams impersonating medical staff.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS02"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},yr={T0078:mr},Ar=e({T0079:()=>br,default:()=>wr}),br={title:"Waybill Data",keywords:["Waybill Data","T0079","Waybill Data control","Waybill Data risk","Waybill Data detection","Waybill Data governance","Waybill Data keyword 7"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to leaked detailed records from express delivery logistics.",description:"These records contain the recipient's name, phone number, address, and purchased item details, serving as a crucial information source for targeted marketing and fraud within the underground economy. This data is typically leaked by insiders at courier companies or through system vulnerabilities, sold in bulk by data brokers, and used for brushing, telecom fraud, or selling counterfeit goods.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0015","A0059","A0021","A0061","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS02"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},wr={T0079:br},Tr=e({T0080:()=>vr,default:()=>Rr}),vr={title:"Domestic Fullz",keywords:["Domestic Fullz","T0080","Domestic Fullz control","Domestic Fullz risk","Domestic Fullz detection","Domestic Fullz governance","Domestic Fullz keyword 7"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to the four core pieces of information for a domestic bank card: the card number, password, cardholder's ID number, and linked mobile phone number.",description:"These four pieces of data are critical for conducting unauthorized transactions, money laundering, and account takeovers, typically obtained through phishing sites, trojans, or system vulnerabilities. Underground groups use them to directly transfer funds or register fake accounts for money laundering through transaction splitting, posing a direct threat to personal financial security.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0007","A0016-003","A0024","A0021","A0006-005","A0016-002","A0051","A0037","A0049","A0054"],relatedAttackTools:["AT0039"],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS01"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Rr={T0080:vr},Br=e({T0081:()=>Dr,default:()=>Sr}),Dr={title:"Customs Data",keywords:["Customs Data","T0081","Customs Data control","Customs Data risk","Customs Data detection","Customs Data governance","Customs Data keyword 7","Customs Data keyword 8","Customs Data keyword 9"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to personal or logistics data stolen during the customs clearance of overseas shipments, packaged and sold as “customs clearance material.”",description:"This type of data typically leaks through cross-border logistics processes and includes sensitive information such as recipient identity, addresses, and phone numbers. Black-market actors intercept data at customs clearance nodes via insiders or system vulnerabilities, then sort and sell it based on freshness and completeness. Downstream buyers often use it for precision fraud, marketing harassment, or identity theft. Due to its high timeliness, this data can be monetized quickly in the short term.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Sr={T0081:Dr},Lr=e({T0082:()=>Cr,default:()=>Fr}),Cr={title:"Real-Time Data",keywords:["Real-Time Data","T0082","Real-Time Data control","Real-Time Data risk","Real-Time Data detection","Real-Time Data governance","Real-Time Data keyword 7","Real-Time Data keyword 8","Real-Time Data keyword 9"],aliases:[],category:"Data Leakage",definition:"Refers to freshly stolen, first-hand personal or organizational data that has not been resold, commanding the highest price on the black market due to its timeliness.",description:"Real-time material emphasizes data freshness and immediate usability, often sourced from recent system intrusions, insider leaks, or phishing harvests. Black-market actors quickly distribute it through automated card-selling platforms or darknet groups, aiming to monetize it before it becomes obsolete. Buyers typically use it for real-time fraud, credential-stuffing attacks, or registering malicious accounts, as shorter delays yield higher success rates.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0006-005","A0016-002","A0051","A0037","A0049"],relatedAttackTools:["AT0027"],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Fr={T0082:Cr},xr=e({T0083:()=>Mr,default:()=>Ir}),Mr={title:"Dead Data",keywords:["Dead Data","T0083","Dead Data control","Dead Data risk","Dead Data detection","Dead Data governance","Dead Data keyword 7","Dead Data keyword 8","Dead Data keyword 9"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to personal or organizational data that has expired and can no longer be exploited, regarded as worthless inventory within the black market.",description:"Dead material loses its utility due to age, information changes, or upgraded platform risk controls, such as deactivated phone numbers, frozen bank cards, or invalid login credentials. This data finds no buyers on the market and is sometimes mixed into data packs to deceive inexperienced downstream purchasers. Once identified as dead material, it is typically discarded and cannot be used in subsequent fraud or marketing operations.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0007","A0016-003","A0024","A0021","A0049","A0054"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS01"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Ir={T0083:Mr},Er=e({T0084:()=>zr,default:()=>Hr}),zr={title:"Redirect / Oauth Account",keywords:["Redirect / Oauth Account","T0084","Redirect / Oauth Account control","Redirect / Oauth Account risk","Redirect / Oauth Account detection","Redirect / Oauth Account governance","Redirect / Oauth Account keyword 7","Redirect / Oauth Account keyword 8","Redirect / Oauth Account keyword 9"],aliases:[],category:"Data Leakage",definition:"Refers to Weibo, WeChat, or QQ accounts whose core functions have been restricted by the platform but can still be used to authorize logins on other platforms, sold cheaply by black-market actors for secondary exploitation.",description:"These accounts have typically been flagged for bulk activity, bonus abuse, or malicious registration, resulting in restrictions on posting, payments, and other core functions. However, their authorization login interfaces remain functional, allowing black-market actors to package them as “redirect accounts” and sell them to bypass registration barriers on other platforms. Buyers use these accounts for operations such as astroturfing, traffic diversion scams, or cross-platform bonus harvesting, benefiting from low costs and delayed bans.",relatedRisks:["R0078","R0089","R0092","R0109"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0006-005","A0016-002","A0051","A0037","A0015","A0059","A0021","A0061"],relatedAttackTools:["AT0012","AT0064"],relatedThreatActors:["TA0005","TA0040","TA0018"],relatedBusinessScenes:["BS00","BS02"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Hr={T0084:zr},Pr=e({T0085:()=>Or,default:()=>qr}),Or={title:"International Fullz",keywords:["International Fullz","T0085","International Fullz control","International Fullz risk","International Fullz detection","International Fullz governance","International Fullz keyword 7","International Fullz keyword 8"],aliases:[],category:"Data Leakage",definition:"Refers to four types of overseas bank card information—card number, password, cardholder ID number, and linked phone number—known in the black market as “foreign material” or “CVV fullz.”",description:"Foreign material primarily originates from data breaches involving overseas cards, including phishing sites, payment interface hijacking, or darknet database dumps. Black-market actors sell these full sets to downstream buyers for cross-border carding, fraudulent transactions, or impersonation-based telecom fraud. Due to the involvement of overseas cards, tracing is difficult, and the laundering process often integrates with underground money-transfer platforms, making the cash-out path covert. Once such information enters the market, cardholders face direct financial loss and identity theft risks.",relatedRisks:["R0078","R0089","R0092","R0109"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0007","A0016-003","A0024","A0021","A0006-005","A0016-002","A0051","A0037","A0049","A0054"],relatedAttackTools:["AT0039","AT0012","AT0064"],relatedThreatActors:["TA0005","TA0040","TA0018"],relatedBusinessScenes:["BS00","BS01"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},qr={T0085:Or},Ur=e({T0086:()=>Nr,default:()=>Wr}),Nr={title:"Dating Data",keywords:["Dating Data","T0086","Dating Data control","Dating Data risk","Dating Data detection","Dating Data governance","Dating Data keyword 7","Dating Data keyword 8","Dating Data keyword 9"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to user personal information packages illegally obtained from dating or matchmaking platforms, internally called “dating material.”",description:"Dating material typically includes personal profiles, contact details, photos, and dating preferences, often leaked by insiders or harvested via web scraping. Black-market actors categorize and sell this data by age, location, and asset status to marketing gangs or fraud rings. Downstream buyers frequently use it to carry out “pig-butchering” scams, emotional manipulation, or targeted matchmaking service promotions, exploiting the data’s high authenticity to lower victims’ defenses.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049","A0051","A0006-005"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS04","BS01","BS02"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Wr={T0086:Nr},jr=e({T0087:()=>Vr,default:()=>Gr}),Vr={title:"First-Hand Data",keywords:["First-Hand Data","T0087","First-Hand Data control","First-Hand Data risk","First-Hand Data detection","First-Hand Data governance","First-Hand Data keyword 7","First-Hand Data keyword 8","First-Hand Data keyword 9"],aliases:[],category:"Data Leakage",definition:"Refers to personal or organizational data obtained directly from the breach source without any intermediary resale, commanding a premium in black-market trading due to its high integrity.",description:"First-hand material avoids the contamination and adulteration caused by multiple resales and typically comes directly from data sources such as insiders, system vulnerabilities, or real-time phishing results. Black-market actors prioritize using first-hand material for high-value fraud or precision marketing because its completeness and strong correlations yield much higher conversion rates than second-hand material. Sellers often advertise “first-hand supply” to attract buyers, though actual transactions may include dead or duplicate data to inflate volumes.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0006-005","A0016-002","A0051","A0037","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Gr={T0087:Vr},Kr=e({T0088:()=>Yr,default:()=>Qr}),Yr={title:"Stock Advisory Lead Data",keywords:["Stock Advisory Lead Data","T0088","Stock Advisory Lead Data control","Stock Advisory Lead Data risk","Stock Advisory Lead Data detection","Stock Advisory Lead Data governance","Stock Advisory Lead Data keyword 7","Stock Advisory Lead Data keyword 8","Stock Advisory Lead Data keyword 9"],aliases:[],category:"Data Leakage",definition:"In illicit data trading, refers to sensitive customer information illegally obtained from stock investment platforms or advisory firms, known in the black market as “stock advisory material.”",description:"This data covers personal identities, transaction records, portfolio preferences, and contact details, often leaked by internal employees or obtained through system intrusions. Black-market actors resell stock advisory material to investment scam rings, illegal margin-trading platforms, or precision marketing agencies, who use it for fraudulent investment inducement, fake stock recommendations, or charging exorbitant service fees. Victims are easily misled into believing the scammers are legitimate advisors due to the precise matching of their personal investment profiles, ultimately resulting in financial loss.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Qr={T0088:Yr},Xr=e({T0089:()=>_r,default:()=>Jr}),_r={title:"Record Lookup",keywords:["Record Lookup","T0089","Record Lookup control","Record Lookup risk","Record Lookup detection","Record Lookup governance","Record Lookup keyword 7","Record Lookup keyword 8","Record Lookup keyword 9"],aliases:[],category:"Data Leakage",definition:"A service in which underground criminal groups illegally retrieve a target's complete personal dossier using a single piece of information, such as a phone number.",description:"File retrieval is a core service in underground data trading. Criminals leverage insider access, system vulnerabilities, or previously breached databases to provide clients with detailed personal records. The service covers highly sensitive data, including identity information, bank card numbers, asset holdings, and hotel stay records. Typically charged per query, this service is a critical source of intelligence for downstream crimes such as fraud, extortion, and precision marketing.",relatedRisks:["R0092","R0078","R0089","R0109"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0007","A0016-003","A0024","A0021","A0049","A0054"],relatedAttackTools:["AT0012","AT0064"],relatedThreatActors:["TA0005","TA0040","TA0018"],relatedBusinessScenes:["BS00","BS01"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Jr={T0089:_r},Zr=e({T0090:()=>$r,default:()=>ei}),$r={title:"Decryption",keywords:["Decryption","T0090","Decryption control","Decryption risk","Decryption detection","Decryption governance","Decryption keyword 7","Decryption keyword 8","Decryption keyword 9"],aliases:[],category:"Data Leakage",definition:"An operation in which criminals restore full phone numbers from partially masked information on privacy-enhanced express delivery waybills.",description:"Decryption services primarily serve telecom fraud rings and underground marketing operations, forming a critical link in the express information leakage chain. Operators illegally obtain waybill numbers and their corresponding virtual or masked phone numbers, then restore the full number using internal system access or cracking tools. Once obtained, the complete phone numbers are used for precision scams, advertising, or resale, directly violating user privacy.",relatedRisks:["R0092","R0078","R0089","R0109"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0007","A0016-003","A0024","A0021","A0049"],relatedAttackTools:["AT0012","AT0064"],relatedThreatActors:["TA0005","TA0040","TA0018"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},ei={T0090:$r},ai=e({T0091:()=>ti,default:()=>ri}),ti={title:"Doxing",keywords:["Doxing","T0091","Doxing control","Doxing risk","Doxing detection","Doxing governance","Doxing keyword 7","Doxing keyword 8","Doxing keyword 9"],aliases:[],category:"Data Leakage",definition:"The act of illegally obtaining and publicly exposing an individual's private data, carried out by underground actors.",description:"Doxing is a common malicious exposure tactic in the cyber underground, typically conducted in anonymous group chats or on social platforms. Perpetrators aggregate fragmented information from social engineering databases, leaked data dumps, and other sources to assemble a complete dossier, including ID numbers, home addresses, social connections, and financial records. Often motivated by revenge, notoriety, or extortion, this practice poses a severe threat to the victim's personal safety and reputation.",relatedRisks:["R0092","R0078","R0089","R0109"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:["AT0012","AT0064"],relatedThreatActors:["TA0005","TA0040","TA0018"],relatedBusinessScenes:["BS00","BS04"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},ri={T0091:ti},ii=e({T0092:()=>ni,default:()=>oi}),ni={title:"Database Operator",keywords:["Database Operator","T0092","Database Operator control","Database Operator risk","Database Operator detection","Database Operator governance","Database Operator keyword 7","Database Operator keyword 8","Database Operator keyword 9"],aliases:[],category:"Data Leakage",definition:"A key figure in underground data trading who owns and operates large-scale databases of leaked information.",description:"The database owner is a top-tier role in the underground data ecosystem, responsible for illegally acquiring, organizing, and continuously updating various social engineering and credential-stuffing databases. By purchasing data from material suppliers or conducting their own attacks, they amass vast amounts of sensitive information and offer query, subscription, or bulk sale services to data buyers. They build and maintain the core infrastructure of underground data trading and are the source of leaked data circulation.",relatedRisks:["R0092","R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:["AT0012"],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},oi={T0092:ni},si=e({T0093:()=>li,default:()=>di}),li={title:"Data Supplier",keywords:["Data Supplier","T0093","Data Supplier control","Data Supplier risk","Data Supplier detection","Data Supplier governance","Data Supplier keyword 7","Data Supplier keyword 8","Data Supplier keyword 9"],aliases:[],category:"Data Leakage",definition:"A primary individual or organization in the underground supply chain that controls and sells first-hand leaked data in bulk.",description:"The material supplier is the direct controller of the data breach source. They obtain fresh data through insider moles, hacking attacks, or vulnerability exploitation, then categorize and organize it. As the upstream source in underground trading, they wholesale data at high prices to downstream buyers, acting as the original supplier for various crimes like fraud and identity theft. They typically only handle the data supply and avoid direct involvement in end-user crimes to minimize their own risk.",relatedRisks:["R0072-001","R0111","R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0024","TA0005","TA0040"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},di={T0093:li},ci=e({T0094:()=>ui,default:()=>hi}),ui={title:"Data Buyer",keywords:["Data Buyer","T0094","Data Buyer control","Data Buyer risk","Data Buyer detection","Data Buyer governance","Data Buyer keyword 7","Data Buyer keyword 8","Data Buyer keyword 9"],aliases:[],category:"Data Leakage",definition:"An individual or organization in the underground supply chain that purchases and uses leaked data for illegal activities.",description:"The data buyer is the end consumer or secondary distributor in underground data trading. They purchase various types of data from material suppliers or data shops and convert it into actual criminal profit. Common downstream activities include financial fraud, bank card theft, social engineering attacks, or reselling the data. They are the direct executors of the harm caused by leaked data, turning the risk of information misuse into reality.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049","A0024","A0054"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS01","BS04"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},hi={T0094:ui},pi=e({T0095:()=>gi,default:()=>ki}),gi={title:"Data Marketplace",keywords:["Data Marketplace","T0095","Data Marketplace control","Data Marketplace risk","Data Marketplace detection","Data Marketplace governance","Data Marketplace keyword 7","Data Marketplace keyword 8","Data Marketplace keyword 9"],aliases:[],category:"Data Leakage",definition:"A platform or site on the black market specifically for trading carding information, such as CVV data.",description:"A carding shop is an online marketplace in the credit card fraud industry chain. Stocked by numerous material suppliers, it primarily sells 'material' containing card numbers, expiration dates, and CVV codes. Transactions are typically settled in cryptocurrency to evade oversight, with the shop itself providing escrow and arbitration services. Such platforms significantly lower the barrier to entry for carding crimes, allowing buyers without hacking skills to easily acquire criminal tools.",relatedRisks:["R0078","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049","A0024","A0054"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS01"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},ki={T0095:gi},fi=e({T0096:()=>mi,default:()=>yi}),mi={title:"Fuzzy Lookup",keywords:["Fuzzy Lookup","T0096","Fuzzy Lookup control","Fuzzy Lookup risk","Fuzzy Lookup detection","Fuzzy Lookup governance","Fuzzy Lookup keyword 7","Fuzzy Lookup keyword 8","Fuzzy Lookup keyword 9"],aliases:[],category:"Data Leakage",definition:"A technique used in social engineering databases to precisely locate a target's data by filtering results with auxiliary fields when only vague information like a name is known.",description:"Demon hunting is a common query technique in social engineering databases. When an attacker only knows a target's name, they cross-reference the returned results with auxiliary information like birthdate, region, and gender. This method allows them to precisely filter a specific target's complete dossier from a massive pool of homonymous data. This technique is a critical step in executing precision scams and doxing.",relatedRisks:["R0092","R0078","R0089","R0109"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:["AT0012","AT0064"],relatedThreatActors:["TA0005","TA0040","TA0018"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},yi={T0096:mi},Ai=e({T0097:()=>bi,default:()=>wi}),bi={title:"Database Sale",keywords:["Database Sale","T0097","Database Sale control","Database Sale risk","Database Sale detection","Database Sale governance","Database Sale keyword 7","Database Sale keyword 8","Database Sale keyword 9"],aliases:[],category:"Data Leakage",definition:"The practice of selling stolen databases in bulk through illicit channels.",description:"Fraudsters package sensitive data—such as personal information, account credentials, and passwords—obtained through various means and sell them at fixed prices on dark web forums or encrypted chat groups. Sellers often exaggerate data freshness and accuracy to inflate prices, while buyers use the data for targeted scams, brute-force attacks, or resale. This activity directly fuels downstream crime and causes large-scale privacy breaches.",relatedRisks:["R0078","R0028","R0089"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0005","TA0040"],relatedBusinessScenes:["BS00","BS04"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},wi={T0097:bi},Ti=e({T0098:()=>vi,default:()=>Ri}),vi={title:"Forced Account Login",keywords:["Forced Account Login","T0098","Forced Account Login control","Forced Account Login risk","Forced Account Login detection","Forced Account Login governance","Forced Account Login keyword 7","Forced Account Login keyword 8","Forced Account Login keyword 9"],aliases:[],category:"Data Leakage",definition:"The act of forcibly logging into user accounts using technical means to steal internal sensitive information.",description:"Attackers exploit vulnerabilities or use credential-stuffing techniques to breach platform defenses and forcibly access user account backends, stealing order details, addresses, and other private data. This high-value information is then packaged and sold to downstream fraud or marketing groups. In data-trading advertisements, the term “forced login” is often used to indicate the data’s source and freshness.",relatedRisks:["R0032-001","R0092","R0078","R0089","R0109"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:["AT0042","AT0012","AT0064"],relatedThreatActors:["TA0005","TA0040","TA0018"],relatedBusinessScenes:["BS00"],references:[{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Ri={T0098:vi},Bi=e({T0099:()=>Di,default:()=>Si}),Di={title:"Account Sweeping",keywords:["Account Sweeping","T0099","Account Sweeping control","Account Sweeping risk","Account Sweeping detection","Account Sweeping governance","Account Sweeping keyword 7","Account Sweeping keyword 8","Account Sweeping keyword 9"],aliases:[],category:"Data Leakage",definition:"The illicit use of automated tools to test batches of credentials and filter out valid accounts.",description:"Using previously leaked username-password combinations, fraudsters run scripts to attempt mass logins across multiple platforms, identifying usable accounts. These validated accounts can then be used to steal virtual assets, post illicit content, or serve as raw material for subsequent targeted scams. This practice severely threatens personal account and financial security.",relatedRisks:["R0032-001","R0088","R0090"],relatedAvoidances:["A0050","A0035","A0016","A0052","A0044","A0049"],relatedAttackTools:["AT0042"],relatedThreatActors:[],relatedBusinessScenes:["BS00"],references:[{title:"API Account Enumeration Has Become a Major Threat to Account Security",link:"https://www.threathunter.cn/blog/6a6fd45548f"},{title:"Black Market Big Data: 2024 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-1da6b236-8f6a-4cfe-bd67-9d0e9a8f4a22"},{title:"Black Market Big Data: 2025 H1 Data Leakage Risk Landscape Report",link:"https://www.threathunter.cn/blog/2025"}],updated:"2026-06-16"},Si={T0099:Di};export{xa as $,Kt as A,K as At,ft as B,f as Bt,pr as C,pe as Ct,ar as D,ae as Dt,ir as E,ie as Et,xt as F,x as Ft,at as G,a as Gt,ct as H,c as Ht,Lt as I,L as It,Ka as J,Za as K,Bt as L,B as Lt,Ut as M,U as Mt,Pt as N,P as Nt,Zt as O,Z as Ot,Et as P,E as Pt,Ea as Q,Tt as R,T as Rt,fr as S,fe as St,sr as T,se as Tt,st as U,s as Ut,pt as V,p as Vt,it as W,i as Wt,Ua as X,ja as Y,Pa as Z,xr as _,xe as _t,pi as a,pa as at,Tr as b,Te as bt,ii as c,ia as ct,Xr as d,Xe as dt,La as et,Kr as f,Ke as ft,Er as g,Ee as gt,Pr as h,Pe as ht,fi as i,fa as it,jt as j,j as jt,Xt as k,X as kt,ai as l,aa as lt,Ur as m,Ue as mt,Ti as n,Ta as nt,ci as o,ca as ot,jr as p,je as pt,Xa as q,Ai as r,Aa as rt,si as s,sa as st,Bi as t,Ba as tt,Zr as u,Ze as ut,Lr as v,Le as vt,cr as w,ce as wt,Ar as x,Ae as xt,Br as y,Be as yt,At as z,A as zt};